import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface Feedback {
  customer: string;
  sentiment: string;
  feedback: string;
}

interface CustomerSatisfactionData {
  npsScore: number;
  trend: number[];
  recentFeedback: Feedback[];
}

export default function Widget() {
  const customerData = response.data as CustomerSatisfactionData;
  const { npsScore, trend, recentFeedback } = customerData;
  const isPositive = npsScore >= 0;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1E293B' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 0.5 }}>
              NPS Score
            </Typography>
            <Typography variant="h4" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
              {npsScore}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isPositive ? <TrendingUp sx={{ fontSize: 16, color: '#10B981' }} /> : <TrendingDown sx={{ fontSize: 16, color: '#EF4444' }} />}
              <Typography variant="body2" sx={{ color: isPositive ? '#10B981' : '#EF4444' }}>
                {isPositive ? 'Positive' : 'Negative'}
              </Typography>
            </Stack>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: trend,
                color: '#2196F3',
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: trend.map((_, i) => i), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack spacing={1.5}>
            {recentFeedback.map((feedback, index) => (
              <Box key={index}>
                <Typography variant="body2" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
                  {feedback.customer}
                </Typography>
                <Typography variant="caption" sx={{ color: feedback.sentiment === 'positive' ? '#10B981' : feedback.sentiment === 'neutral' ? '#F59E0B' : '#EF4444' }}>
                  {feedback.feedback}
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
